import { defineConfig } from 'vite'
import react from '@vitejs/plugin-react'

// https://vite.dev/config/
export default defineConfig({
  plugins: [react()],
})

// API Client for AAA (Autonomous Academic Agent)
const DEFAULT_BASE_URL = 'http://127.0.0.1:8000/api/v1';

// Load base URL from environment variable or default
const BASE_URL = import.meta.env.VITE_API_BASE_URL || DEFAULT_BASE_URL;

export class APIError extends Error {
  constructor(status, code, message, details = null) {
    super(message);
    this.status = status;
    this.code = code;
    this.details = details;
  }
}

/**
 * Handle API responses and standardize errors
 */
async function handleResponse(response) {
  if (response.ok) {
    return response.json();
  }

  let errorData;
  let code = 'unknown_error';
  let message = 'An unexpected error occurred';
  let details = null;

  try {
    errorData = await response.json();
    if (errorData?.error) {
      // standard AAA custom error structure: {error: {code, message}}
      code = errorData.error.code || code;
      message = errorData.error.message || message;
    } else if (errorData?.detail) {
      // FastAPI standard validation error or other detail
      code = 'validation_error';
      if (Array.isArray(errorData.detail)) {
        details = errorData.detail;
        message = errorData.detail.map(d => `${d.loc.join('.')}: ${d.msg}`).join(', ');
      } else {
        message = String(errorData.detail);
      }
    }
  } catch (e) {
    // Response was not JSON
    message = `Server responded with status ${response.status}`;
  }

  throw new APIError(response.status, code, message, details);
}

export const api = {
  /**
   * Create student from raw learning goal
   */
  async createStudent(name, rawInput) {
    const response = await fetch(`${BASE_URL}/students`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({ name, raw_input: rawInput }),
    });
    return handleResponse(response);
  },

  /**
   * Create student from PDF syllabus file upload
   */
  async uploadSyllabus(name, file) {
    const formData = new FormData();
    formData.append('name', name);
    formData.append('file', file);

    const response = await fetch(`${BASE_URL}/students/upload-syllabus`, {
      method: 'POST',
      body: formData,
    });
    return handleResponse(response);
  },

  /**
   * Resume session / Get student profile
   */
  async getStudent(studentId) {
    const response = await fetch(`${BASE_URL}/students/${studentId}`);
    return handleResponse(response);
  },

  /**
   * Start pipeline for current/next topic
   */
  async startTopicPipeline(studentId) {
    const response = await fetch(`${BASE_URL}/students/${studentId}/start`, {
      method: 'POST',
    });
    return handleResponse(response);
  },

  /**
   * Fetch lesson content and sources
   */
  async getLesson(studentId) {
    const response = await fetch(`${BASE_URL}/students/${studentId}/lesson`);
    return handleResponse(response);
  },

  /**
   * Fetch quiz questions
   */
  async getQuiz(studentId) {
    const response = await fetch(`${BASE_URL}/students/${studentId}/quiz`);
    return handleResponse(response);
  },

  /**
   * Submit quiz answers
   * answers: [{question_id, answer_text}]
   */
  async submitAnswers(studentId, answers) {
    const response = await fetch(`${BASE_URL}/students/${studentId}/answer`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({ answers }),
    });
    return handleResponse(response);
  },

  /**
   * Fetch full dashboard data
   */
  async getProfile(studentId) {
    const response = await fetch(`${BASE_URL}/students/${studentId}/profile`);
    return handleResponse(response);
  },

  /**
   * Fetch topic list with statuses
   */
  async getTopics(studentId) {
    const response = await fetch(`${BASE_URL}/students/${studentId}/topics`);
    return handleResponse(response);
  },

  /**
   * Health check
   */
  async checkHealth() {
    const response = await fetch(`${BASE_URL}/health`);
    return handleResponse(response);
  }
};
export default api;

import React, { useState, useEffect } from 'react';
import Onboarding from './components/Onboarding';
import SyllabusOverview from './components/SyllabusOverview';
import LessonView from './components/LessonView';
import QuizView from './components/QuizView';
import ProfileView from './components/ProfileView';
import ProgressBar from './components/ProgressBar';
import { api } from './api';

export default function App() {
  const [studentId, setStudentId] = useState(null);
  const [currentScreen, setCurrentScreen] = useState('onboarding'); // onboarding, syllabus, lesson, quiz, profile
  const [studentName, setStudentName] = useState('');
  
  // Progress stats for ProgressBar
  const [progressStats, setProgressStats] = useState({ completed: 0, total: 0 });
  const [loading, setLoading] = useState(true);

  // Attempt to auto-resume student session on mount
  useEffect(() => {
    const resumeSession = async () => {
      const savedStudentId = localStorage.getItem('aaa_student_id');
      if (savedStudentId) {
        try {
          // Verify with backend
          const studentProfile = await api.getStudent(savedStudentId);
          const topics = await api.getTopics(savedStudentId);
          
          setStudentId(savedStudentId);
          setStudentName(studentProfile.name);
          
          // Calculate progress stats
          const completed = topics.filter(t => t.status === 'taught').length;
          setProgressStats({ completed, total: topics.length });
          
          setCurrentScreen('syllabus');
        } catch (err) {
          console.warn('Could not auto-resume session:', err);
          // Clear stale ID
          localStorage.removeItem('aaa_student_id');
          setCurrentScreen('onboarding');
        }
      } else {
        setCurrentScreen('onboarding');
      }
      setLoading(false);
    };

    resumeSession();
  }, []);

  // Sync completion stats periodically or on view transitions
  const syncProgress = async (id) => {
    if (!id) return;
    try {
      const topics = await api.getTopics(id);
      const completed = topics.filter(t => t.status === 'taught').length;
      setProgressStats({ completed, total: topics.length });
    } catch (e) {
      console.warn('Could not sync completion stats:', e);
    }
  };

  const handleStudentCreated = (newId, syllabus) => {
    setStudentId(newId);
    
    // We can extract name from the syllabus response or profile
    api.getStudent(newId).then(profile => {
      setStudentName(profile.name);
    });

    const completed = syllabus.filter(t => t.status === 'taught').length;
    setProgressStats({ completed, total: syllabus.length });
    setCurrentScreen('syllabus');
  };

  const handleLogout = () => {
    localStorage.removeItem('aaa_student_id');
    setStudentId(null);
    setStudentName('');
    setProgressStats({ completed: 0, total: 0 });
    setCurrentScreen('onboarding');
  };

  const handleActionTriggered = (nextAction) => {
    syncProgress(studentId);
    // Based on action returned by evaluate answer, drive the next UI screen
    if (nextAction === 'advance' || nextAction === 'complete') {
      setCurrentScreen('syllabus');
    } else if (nextAction === 'reteach') {
      // Goes back to syllabus, student clicks "Review Lesson" to regenerate from backend
      setCurrentScreen('syllabus');
    } else if (nextAction === 'insert_prerequisite') {
      // Goes back to syllabus to see prerequisite detour in timeline
      setCurrentScreen('syllabus');
    } else {
      setCurrentScreen('syllabus');
    }
  };

  if (loading) {
    return (
      <div className="loading-box" style={{ minHeight: '100vh' }}>
        <div className="academic-spinner"></div>
        <h2 className="loading-text">Resuming academic session...</h2>
      </div>
    );
  }

  return (
    <div className="app-container">
      {/* Top minimal progress bar */}
      {studentId && (
        <ProgressBar
          completedCount={progressStats.completed}
          totalCount={progressStats.total}
        />
      )}

      {/* Header section */}
      <header className="app-header">
        <div className="logo-section" onClick={() => studentId && setCurrentScreen('syllabus')}>
          <span className="logo-icon">🏛️</span>
          <span className="logo-text">Autonomous Academic Agent</span>
        </div>
        
        {studentId && (
          <nav className="nav-section">
            <span
              className={`nav-link ${currentScreen === 'syllabus' ? 'active' : ''}`}
              onClick={() => { syncProgress(studentId); setCurrentScreen('syllabus'); }}
            >
              Syllabus Roadmap
            </span>
            <span
              className={`nav-link ${currentScreen === 'profile' ? 'active' : ''}`}
              onClick={() => setCurrentScreen('profile')}
            >
              Progress Log
            </span>
            <button
              onClick={handleLogout}
              className="btn btn-secondary"
              style={{ fontSize: '0.8rem', padding: '0.4rem 0.8rem' }}
            >
              Change Student
            </button>
          </nav>
        )}
      </header>

      {/* Main page router */}
      <main style={{ flex: 1 }}>
        {currentScreen === 'onboarding' && (
          <Onboarding onStudentCreated={handleStudentCreated} />
        )}

        {currentScreen === 'syllabus' && studentId && (
          <SyllabusOverview
            studentId={studentId}
            onStartLesson={() => setCurrentScreen('lesson')}
            onSelectProfile={() => setCurrentScreen('profile')}
          />
        )}

        {currentScreen === 'lesson' && studentId && (
          <LessonView
            studentId={studentId}
            onStartQuiz={() => setCurrentScreen('quiz')}
            onBackToSyllabus={() => { syncProgress(studentId); setCurrentScreen('syllabus'); }}
          />
        )}

        {currentScreen === 'quiz' && studentId && (
          <QuizView
            studentId={studentId}
            onBackToSyllabus={() => { syncProgress(studentId); setCurrentScreen('syllabus'); }}
            onActionTriggered={handleActionTriggered}
          />
        )}

        {currentScreen === 'profile' && studentId && (
          <ProfileView
            studentId={studentId}
            onBack={() => setCurrentScreen('syllabus')}
          />
        )}
      </main>
    </div>
  );
}

// Common helper utilities for AAA frontend

/**
 * Format ISO datetime string to friendly readable text
 */
export function formatDateTime(isoString) {
  if (!isoString) return 'Never';
  try {
    const date = new Date(isoString);
    if (isNaN(date.getTime())) return isoString;
    return date.toLocaleDateString(undefined, {
      month: 'long',
      day: 'numeric',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  } catch (e) {
    return isoString;
  }
}

/**
 * Maps API topic status to human-readable labels
 */
export const STATUS_MAP = {
  pending: { label: 'Pending', color: 'var(--color-text-muted)', bg: '#FAF9F6' },
  in_progress: { label: 'In Progress', color: '#B37D22', bg: '#FDF7E7' },
  taught: { label: 'Taught', color: 'var(--color-accent-mastery)', bg: 'var(--color-accent-mastery-light)' },
  weak: { label: 'Needs Review', color: 'var(--color-accent-rust)', bg: 'var(--color-accent-rust-light)' },
  strong: { label: 'Mastered', color: 'var(--color-accent-mastery)', bg: 'var(--color-accent-mastery-light)' },
  critical: { label: 'Gaps Found', color: 'var(--color-accent-rust)', bg: 'var(--color-accent-rust-light)' }
};

/**
 * Mapping topic difficulty levels
 */
export const DIFFICULTY_MAP = {
  beginner: { label: 'Beginner', class: 'diff-beginner' },
  intermediate: { label: 'Intermediate', class: 'diff-intermediate' },
  advanced: { label: 'Advanced', class: 'diff-advanced' }
};

/**
 * Mapping API next_action values to helpful student descriptions
 */
export const NEXT_ACTION_MAP = {
  advance: {
    title: 'Topic Mastered',
    description: 'You have shown excellent comprehension. Let\'s move forward to the next topic in the curriculum.',
    buttonText: 'Advance to Next Lesson'
  },
  complete: {
    title: 'Curriculum Completed',
    description: 'Congratulations! You have completed all the topics in this syllabus and mastered the core concepts.',
    buttonText: 'View Final Syllabus'
  },
  reteach: {
    title: 'Let\'s Review',
    description: 'We\'ve identified some concepts that need reinforcing. Let\'s go over this topic again from a different perspective to solidify your understanding.',
    buttonText: 'Review Lesson'
  },
  insert_prerequisite: {
    title: 'Prerequisite Detour',
    description: 'To help you master this concept, we have identified and inserted a necessary prerequisite topic into your path. Let\'s build this foundation first.',
    buttonText: 'Begin Prerequisite Lesson'
  }
};

